        #gameContainer {
            position: relative;
            width: 360px;
            height: 640px;
        }
        #gameCanvas {
            width: 360px;
            height: 640px;
            border-radius: 12px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
            display: block;
            margin: 0 auto;
            background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
        }
        .overlay {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
